import{_ as h,g as i,f as t,z as g}from"./chunks/framework.pU9sRy1K.js";const d=JSON.parse('{"title":"Kinh Đời Sống Gia Đình","description":"Bốn điều kiện để vợ chồng sống hạnh phúc, hòa hợp trong đời sống tại gia.","frontmatter":{"code":"AN 4.55","title":"Kinh Đời Sống Gia Đình","pali":"Samajīvinā Sutta","group":"Chương Bốn pháp – Năm pháp","translation":"thich-minh-chau","book":"tang-chi-bo","description":"Bốn điều kiện để vợ chồng sống hạnh phúc, hòa hợp trong đời sống tại gia."},"headers":[],"relativePath":"kinh/tang-chi-bo/thich-minh-chau/an-4-55-kinh-doi-song-gia-dinh.md","filePath":"kinh/tang-chi-bo/thich-minh-chau/an-4-55-kinh-doi-song-gia-dinh.md","lastUpdated":1782983601000}'),a={name:"kinh/tang-chi-bo/thich-minh-chau/an-4-55-kinh-doi-song-gia-dinh.md"};function c(o,n,s,p,r,e){return i(),t("div",null,[...n[0]||(n[0]=[g("<p><em>Như vầy tôi nghe.</em></p><p>Một thời Thế Tôn trú tại Savatthi. Tại đó, Thế Tôn nói với các Tỳ-kheo:</p><p>&quot;Này các Tỷ-kheo, có bốn điều kiện để vợ chồng sống hòa hợp, hạnh phúc trong đời sống tại gia. Thế nào là bốn?</p><p><strong>Thứ nhất</strong>, vợ chồng cùng đức hạnh — cùng giữ giới, cùng tin vào nhân quả.</p><p><strong>Thứ hai</strong>, cùng lòng tin — cùng tin tưởng lẫn nhau, không nghi ngờ, không giấu giếm.</p><p><strong>Thứ ba</strong>, cùng sự hi sinh — sẵn sàng hy sinh vì nhau, chia sẻ gánh nặng trong đời sống.</p><p><strong>Thứ tư</strong>, cùng trí tuệ — cùng hiểu biết, cùng quyết định những việc quan trọng của gia đình.</p><p>Này các Tỷ-kheo, khi vợ chồng có đủ bốn điều kiện này, họ sẽ sống hòa hợp như hai dòng nước hội nhập, không tách rời trong cả đời hiện tại lẫn đời sau.&quot;</p><hr>",9)])])}const _=h(a,[["render",c]]);export{d as __pageData,_ as default};
